import{_ as i,o as n,c as a,ag as r}from"./chunks/framework.DXGyWiRo.js";const t="/images/lekt0201.jpg",s="/images/lekt0203.jpg",l="/images/lekt0202.jpg",b=JSON.parse('{"title":"Lektion 2","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion02.md","filePath":"lektionen/lektion02.md"}'),u={name:"lektionen/lektion02.md"};function d(o,e,h,m,c,g){return n(),a("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-2" tabindex="-1">Lektion 2 <a class="header-anchor" href="#lektion-2" aria-label="Permalink to &quot;Lektion 2&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>2.1. Der Nominalsatz</li><li>2.2. Zur Deklination (Beugung von Nomina)</li><li>2.3. Der Nominativ Singular = prathamā ekavacanam = प्रथमा एकवचनम् <ul><li>2.3.1. Nominativ Singular auf -s</li></ul></li><li>2.4. Sandhi -- सन्धि <ul><li>2.4.1. Sandhi von auslautendem -s</li></ul></li><li>2.5. Wortliste</li><li>2.6. Übung</li></ul><h2 id="_2-1-der-nominalsatz" tabindex="-1">2.1. Der Nominalsatz <a class="header-anchor" href="#_2-1-der-nominalsatz" aria-label="Permalink to &quot;2.1. Der Nominalsatz&quot;">​</a></h2><p>Schema: Prädikatsnomen - Subjekt</p><p>z.B. devo viṣṇuḥ = देवो विष्णुः = &quot;Viṣṇu ist ein Gott.&quot;</p><p>Eine verbale Kopula (&quot;ist&quot;, &quot;sind&quot;, &quot;bin&quot;, &quot;bist&quot;, &quot;seid&quot;) ist nicht nötig, kann aber manchmal vorkommen.</p><p>Es gibt keine Artikel: devaḥ -- देवः kann bedeuten &quot;der Gott&quot; oder &quot;ein Gott&quot;.</p><p>Obwohl im Sanskrit die Satzstellung ziemlich frei ist (besonders in Versen), muss man bei der Übersetzung eines Nominalsatzes immer in erster Linie eine Übersetzung gemäß obigem Standardschema in Betracht ziehen.</p><p>Im Nominalsatz steht das Subjekt im Nominativ (ersten Fall = prathamā f. = प्रथमा). Das Prädikatsnomen stimmt mit dem Subjekt in Zahl und Fall überein; wenn das Prädikatsnomen ein Adjektiv ist, auch im Geschlecht.</p><h2 id="_2-2-zur-deklination-beugung-von-nomina" tabindex="-1">2.2. Zur Deklination (Beugung von Nomina) <a class="header-anchor" href="#_2-2-zur-deklination-beugung-von-nomina" aria-label="Permalink to &quot;2.2. Zur Deklination (Beugung von Nomina)&quot;">​</a></h2><p>Im Sanskrit gibt es</p><ul><li>drei Numeri (Zählformen) = vacana n. -- वचन <ul><li>Singular (Einzahl) = ekavacana n. -- एकवचन</li><li>Dual (Zweizahl) = dvivacana n. -- द्विवचन</li><li>Plural (Mehrzahl) = bahuvacana n. -- बहुवचन</li></ul></li><li>drei Genera (grammatische Geschlechter) = liṅga n. / vyakti f. -- लिङ्ग / व्यक्ति <ul><li>Maskulinum (männliches grammatisches Geschlecht) = puṃs m. -- पुंस्</li><li>Femininum (weibliches grammatisches Geschlecht) = strī f. -- स्त्री</li><li>Neutrum (sächliches grammatisches Geschlecht) = napuṃsaka n. -- नपुंसक</li></ul></li><li>acht Kasus (Fälle) = sup -- सुप् (= Kasusendungen)</li></ul><p>Zur Deklination treten die Kasusendungen (sup = सुप्) an den sogenannten Nominalstamm (Form des Nomens ohne Kasusendungen). So z.B. devas = देवस् (Nominativ Singular Maskulinum = erster Fall Einzahl männlich = prathamā ekavacanam puṃs = प्रथमा एकवचनम् पुंस्) &quot;der/ein Gott&quot; = deva- -- देव- (Nominalstamm) + -s -- -स् (Kasusendung des Nominativ Singular)</p><p>In Sanskritwörterbüchern und -grammatiken werden Nomina nicht im Nominativ Singular (erster Fall Einzahl, prathamā ekavacanam) (wie z.B. im Lateinischen) angeführt, sondern in der Form des (bei mehrstämmigen Nomina: eines) Nominalstamms, z.B.</p><ul><li>&quot;deva m.&quot; --  &quot;देव m.&quot; (maskulin)</li><li>&quot;vacana n.&quot; -- &quot;वचन&quot; n.&quot; (neutrum)</li><li>&quot;vyakti f.&quot; -- &quot;व्यक्ति f.&quot; (femininum)</li></ul><h2 id="_2-3-der-nominativ-singular-prathama-ekavacanam-प्रथमा-एकवचनम्" tabindex="-1">2.3. Der Nominativ Singular = prathamā ekavacanam = प्रथमा एकवचनम् <a class="header-anchor" href="#_2-3-der-nominativ-singular-prathama-ekavacanam-प्रथमा-एकवचनम्" aria-label="Permalink to &quot;2.3. Der Nominativ Singular = prathamā ekavacanam = प्रथमा एकवचनम्&quot;">​</a></h2><p>Der Nominativ Singular (prathamā ekavacana) endet auf -s = -स् bzw. ist endungsfrei</p><h3 id="_2-3-1-nominativ-singular-auf-s" tabindex="-1">2.3.1. Nominativ Singular auf -s <a class="header-anchor" href="#_2-3-1-nominativ-singular-auf-s" aria-label="Permalink to &quot;2.3.1. Nominativ Singular auf -s&quot;">​</a></h3><p>Folgende Nominalstämme die mit einem Vokal enden, bilden den Nominativ Singular auf -s:</p><ul><li>Maskulina auf -a: z.B. deva m. = देव &quot;Gott, Himmlischer&quot; -- Nom. sg.: devas = देवस्</li><li>Maskulina auf -i: z.B. kavi m. = कवि &quot;Dichter&quot; -- Nom. sg.: kavis = कविस्</li><li>Maskulina auf -u: z.B. guru m. = गुरु &quot;Meister, Lehrer&quot; -- Nom. sg.: gurus = गुरुस्</li></ul><h2 id="_2-4-sandhi-सन्धि" tabindex="-1">2.4. Sandhi -- सन्धि <a class="header-anchor" href="#_2-4-sandhi-सन्धि" aria-label="Permalink to &quot;2.4. Sandhi -- सन्धि&quot;">​</a></h2><p>Der Auslaut eines Wortes richtet sich im Sanskrit auch nach dem Anlaut des darauffolgenden Wortes. Diese Erscheinung nennt man sandhi (m.) = सन्धि (&quot;Verbindung&quot;).</p><h3 id="_2-4-1-sandhi-von-auslautendem-s" tabindex="-1">2.4.1. Sandhi von auslautendem -s <a class="header-anchor" href="#_2-4-1-sandhi-von-auslautendem-s" aria-label="Permalink to &quot;2.4.1. Sandhi von auslautendem -s&quot;">​</a></h3><p>Siehe auch die Übersicht:</p><blockquote><p>Payer, Alois &lt;1944 - &gt;: Sandhi von auslautendem -s. -- (Materialien zum Sanskrit). -- URL: <a href="http://www.payer.de/sanskritmaterialien/ssandhi.htm" target="_blank" rel="noreferrer">http://www.payer.de/sanskritmaterialien/ssandhi.htm</a></p></blockquote><p>Auslautendes -s</p><ul><li>im absoluten Auslaut (Satzende, Versende) wird ersetzt durch Visarga (-ḥ):<br> z.B.<br> devas = देवस् » devaḥ = देवः<br> kavis = कविस् » kaviḥ = कविः<br> gurus = गुरुस् » guruḥ = गुरुः</li><li>vor stimmlosen Lauten: <ul><li>vor stimmlosen Gutturalen (k, kh): wird ersetzt durch Visarga (-ḥ)</li><li>vor stimmlosen Labialen (p, ph): wird ersetzt durch Visarga (-ḥ)</li><li>vor stimmlosen Zischlauten (ś, ṣ, s): wird ersetzt durch Visarga (-ḥ)<br> z.B.<br> devas + śivaḥ » devaḥ śivaḥ = देवः शिवः  &quot;Śiva ist ein Gott&quot;<br> kavis + kālidāsas  » kaviḥ kālidāsaḥ = कविः कालिदासः &quot;Kālidāsa ist ein Dichter&quot;</li><li>vor stimmlosen Palatalen (c, ch): wird ersetzt durch -ś</li><li>vor stimmlosen Retroflexen (ṭ, ṭh): wird ersetzt durch -ṣ</li><li>vor stimmlosen Dentalen (t, th): bleibt -s<br> (d.h. in diesen Fällen steht der Zischlaut der Klasse des Anlauts)<br> z.B.<br> sādhus + caitanyas  » sādhuś caitanyaḥ = साधुश्चैतन्यः &quot;Caitanya ist ein Heiliger&quot;</li></ul></li><li>vor stimmhaften Lauten: <ul><li>nach Nicht-a-Vokalen (außer vor r-): wird ersetzt durch -r<br> z.B.<br> kavis + Māghas  » kavir māghaḥ = कविर्माघः &quot;Māgha ist ein Dichter&quot;</li><li>nach Nicht-a-Vokalen vor r-: -s fällt aus, ein dem -s vorhergehender kurzer Vokal wird durch den entsprechenden langen Vokal ersetzt, ein vorausgehender langer Vokal bleibt unverändert<br> z.B.<br> gurus + rāmas  » gurū rāmaḥ = गुरू रामः &quot;Rāma ist ein Lehrer&quot;</li><li>nach a-: auslautendes -as <ul><li>vor stimmhaften Konsonanten und vor a: wird ersetzt durch -o, anlautendes a- fällt nach diesem -o weg<br> z.B.<br> devas viṣṇus  » devo viṣṇuḥ = देवो विष्णुः &quot;Viṣṇu ist ein Gott&quot;<br> devas agnis  » devo &#39;gniḥ = देवो ऽग्निः&quot;Agni (Feuer) ist ein Gott&quot;</li><li>vor anderen Vokalen als -a: -as wird ersetzt durch -a mit Hiatus<br> z.B.<br> devas + indras  » deva indraḥ = देव इन्द्रः &quot;Indra ist ein Gott&quot;</li></ul></li></ul></li></ul><h2 id="_2-5-wortliste" tabindex="-1">2.5. Wortliste <a class="header-anchor" href="#_2-5-wortliste" aria-label="Permalink to &quot;2.5. Wortliste&quot;">​</a></h2><p>Lernen Sie folgende Wörter:</p><p>deva m. -- देव : Himmlischer, Gott ; Fürst, König (besonders in Anrede)</p><p>īśvara m. -- ईश्वर : Herr, Herrscher, oberste Gottheit, Gott (im monotheistischen Sinn)</p><p>brāhmaṇa m. -- ब्राह्मण : Brahmane, Angehöriger des ersten Stands (varṇa m.), des geistlichen Stands -- Priesterstands -- und Lehrstands.</p><p>kṣatriya m. -- क्षत्रिय : Kṣatriya, Angehöriger des zweiten Stands (varṇa m.), des Fürstenstands und Wehrstands</p><p>vaiśya m. -- वैश्य : Vaiṣya, Angehöriger des dritten Stands (varṇa m.), des Nährstands und Händlerstands</p><p>śūdra m. -- शूद्र : Śūdra, Angehöriger des vierten Stands (varṇa m.), des Knechtstands und Dienstleistungsstands (Handwerker usw.)</p><blockquote><p>Nach der klassischen Theorie (z.B. Manusmṛti i, 88-91) ist Aufgabe</p><ul><li>der Brahmanen <ul><li>Vedastudium</li><li>Lehre</li><li>Opfer für sich</li><li>Opfer für andere</li><li>Geben</li><li>Empfangen von Gaben</li></ul></li><li>der Kṣatriyas <ul><li>das Volk schützen</li><li>Gaben (an Brahmanen) geben</li><li>für sich opfern</li><li>Vedastudium</li></ul></li><li>der Vaiśyas <ul><li>Viehhaltung</li><li>Landwirtschaft</li><li>Handel</li><li>Geldverleih</li><li>für sich opfern</li><li>Gaben (an Brahmanen) geben</li><li>Vedastudium</li></ul></li><li>der Śūdras <ul><li>den drei oberen Klassen dienen</li></ul></li></ul></blockquote><p>dvija m. -- द्विज : Zweimalgeborener: Angehöriger eines der drei ersten Stände (varṇa m.); zweimal geboren: einmal natürliche Geburt, das zweite Mal durch die Zeremonie des upanayana (n.), bei der der Knabe initiiert wird; insbesondere: dvija = Brahmane ; dvija auch = Vogel oder ein anderes eigeborenes Lebewesen: sie erscheinen in einer ersten Geburt als Ei, in einer zweiten beim Schlüpfen.</p><p>varṇa m.-- वर्ण : Farbe, Geburtsstand</p><p>Die vier Stände (varṇa m.) werden oft mit Kasten verwechselt. Die vier Stände sind aber -- im Unterschied zu den Kasten -- nichts spezifisch Indisches, auch in Europa hatten wir (teils bis zum Ersten Weltkrieg) eine Ständeordnung, wie folgende Abbildung aus dem 15. Jhdt. belegt:</p><p><img src="'+t+'" alt=""><br> Abb.: Darstellung der Ständeeinteilung des europäischen Mittelalters (Holzschnitt des ausgehenden 15. Jahrhunderts)</p><p>Beschriftung:</p><ul><li>Priesterstand (~Brāhmaṇa): Tu supplex ora = Du bete flehend!</li><li>Adelsstand (~Kṣatriya): Tu protege = Du schütze!</li><li>Bauernstand (~Vaiśya/Śūdra): Tuque labora = Und Du arbeite!</li></ul><p>Die drei Stände tragen die jeweilige Standestracht. Über den - damit als gottgewollt bezeichneten - Ständen trohnt Christus.</p><p>[Bildquelle: Meyer, Werner: Hirsebrei und Hellebarde : auf den Spuren des mittelalterlichen Lebens in der Schweiz . -- 2. Aufl. -- Olten  [u.a.] : Walter, 1986. -- ISBN: 3-530-56707-8. -- S. 129]</p><p>Max Weber &lt;1864 - 1920&gt; definiert Stand so</p><blockquote><p>»Stand« soll eine Vielheit von Menschen heißen, die innerhalb eines Verbandes wirksam</p><ol><li>eine ständische Sonderschätzung, - eventuell also auch</li><li>ständische Sondermonopole in Anspruch nehmen.</li></ol><p>Stände können entstehen</p><ol><li>primär, durch eigene ständische Lebensführung, darunter insbesondere durch die Art des Berufs (Lebensführungs- bzw. Berufsstände),</li><li>sekundär, erbcharismatisch, durch erfolgreiche Prestigeansprüche kraft ständischer Abstammung (Geburtsstände),</li><li>durch ständische Appropriation von politischen oder hierokratischen Herrengewalten als Monopole (politische bzw. hierokratische Stände).</li></ol><p>Die geburtsständische Entwicklung ist regelmäßig eine Form der (erblichen) Appropriation von Privilegien an einen Verband oder an qualifizierte Einzelne. Jede feste Appropriation von Chancen, insbesondere [von] Herren [gewalten oder Erwerbs] chancen, neigt dazu, zur Ständebildung zu führen. Jede Ständebildung neigt dazu, zur monopolistischen Appropriation von Herrengewalten und Erwerbschancen zu führen.</p><p>Während Erwerbsklassen auf dem Boden der marktorientierten Wirtschaft wachsen, entstehen und bestehen Stände vorzugsweise auf dem Boden der monopolistisch leiturgischen oder der feudalen oder der ständisch patrimonialen Bedarfsdeckung von Verbänden.</p><p>»Ständisch« soll eine Gesellschaft heißen, wenn die soziale Gliederung vorzugsweise nach Ständen, »klassenmäßig«, wenn sie vorzugsweise nach Klassen geschieht. Dem »Stand« steht von den »Klassen« die »soziale« Klasse am nächsten, die »Erwerbsklasse« am fernsten. Stände werden oft ihrem Schwerpunkt nach durch Besitzklassen gebildet.</p><p>Jede ständische Gesellschaft ist <em>konventional</em>, durch Regeln der Lebensführung, geordnet, schafft daher ökonomisch irrationale Konsumbedingungen und hindert auf diese Art durch monopolistische Appropriationen und durch Ausschaltung der freien Verfügung über die eigene Erwerbsfähigkeit die freie Marktbildung.&quot;</p><p>[Weber, Max &lt;1864 - 1920&gt;: Wirtschaft und Gesellschaft : Grundriss der verstehenden Soziologie. -- 5., revidierte Aufl., Studienausgabe. --  Tübingen : Mohr, 1976. -- ISBN: 3-16-538521-1. -- S. 625 f.]</p></blockquote><p>Varṇas sind demgemäß Geburtsstände.</p><p>kavi m. -- कवि : Dichter</p><p>agni m. -- अग्नि : Feuer, Gott Agni</p><p><img src="'+s+'" alt=""><br> Abb.: Gott Agni, Miniatur, 18. Jhdt<br> [Bildquelle: Wikipedia, Public domain]</p><p>sādhu 3 -- साधु : richtig, gut</p><p>sādhu m. -- साधु : &quot;heiliger&quot; Mann, Sādhu</p><p><img src="'+l+'" alt=""><br> Abb.: Sādhu (साधु), Pashupatinath Tempel (पशुपतिनाथ मन्दिर), Kathmandu (काठमांडौ), Nepal (नेपाल), 2007<br> [Bildquelle: Peter Akkermans, Wikipedia, GNU FDLizenz]</p><p>guru 3 -- गुरु : schwer, bedeutend, verehrenswert</p><p>guru m. -- गुरु : verehrenswerte Person: Vater, Mutter, älterer Verwandter, insbes. Lehrer, Meister</p><h2 id="_2-6-ubung" tabindex="-1">2.6. Übung <a class="header-anchor" href="#_2-6-ubung" aria-label="Permalink to &quot;2.6. Übung&quot;">​</a></h2><p>A) Setzen Sie in den folgenden Sätzen unter Beachtung des Sandhi die angegebenen Namen und Nomina ein und bilden Sie Nominalsätze:</p><ol><li>devas ... (Śiva, Agni, Viṣṇu, Gaṇeśa, Kṛṣṇa, Indra) = देवस् ... (शिव, अग्नि, विष्णु, गणेश, कृष्ण, इन्द्र)</li><li>dvijas ... (brāhmaṇa, kṣatriya, vaiśya) = द्विजस् ... (ब्राह्मण, क्षत्रिय, वैश्य)</li><li>gurus ... (brāhmaṇa, Candrakīrti) = गुरुस् ... (ब्राह्मण, चन्द्रकीर्ति)</li><li>vaiśyas ... (Tulādhara) = वैश्यस् ... (तुलाधर)</li><li>sādhus ... (guru, Rāma) = साधुस् ... (गुरु, राम)</li><li>kavis ... (Kālidāsa, Māgha, Bhāravi, Harṣadeva) = कविस् ... (कालिदास, माघ, भारवि, हर्षदेव)</li></ol><p>B) Übersetzen Sie ins Sanskrit:</p><ol><li>Rāma ist ein Brahmane.</li><li>Der Lehrer ist ein vaiśya.</li><li>Der Śūdra ist ein heiliger Mann.</li><li>Der Dichter ist der Lehrer.</li><li>Viṣṇu ist der HERR.</li><li>Der HERR ist Śiva.</li><li>Der Zweimalgeborene ist ein Brahmane.</li><li>Der heilige Mann ist ein Lehrer.</li><li>Der Lehrer ist ein heiliger Mann.</li></ol>',62)])])}const v=i(u,[["render",d]]);export{b as __pageData,v as default};
